// Animation variants
const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1
    }
  }
};

const itemVariants = {
  hidden: { y: 30, opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,
    transition: { duration: 0.6, ease: "easeOut" }
  }
};

const Statistics = () => {
  // Estados para animações
  const [selectedTime, setSelectedTime] = useState('mes');
  const [isLoading, setIsLoading] = useState(true);
  const [chartHeight, setChartHeight] = useState([]);
  const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
  const days = ['Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb', 'Dom'];
  const datasets = {
    semana: [35, 48, 52, 46, 58, 64, 72],
    mes: [42, 58, 75, 68, 85, 92, 110, 105, 125, 138, 152, 168],
    ano: [50, 62, 78, 70, 88, 96, 115, 112, 130, 145, 160, 180]
  };
  const labels = selectedTime === 'semana' ? days : months;
  const chartData = chartHeight.map((value, index) => ({ name: labels[index], value }));
  const totalValue = chartData.reduce((sum, item) => sum + item.value, 0);
  const growth = chartData.length > 1 ? ((chartData[chartData.length - 1].value - chartData[chartData.length - 2].value) / chartData[chartData.length - 2].value) * 100 : 0;
  const maxValue = chartData.length ? Math.max(...chartData.map(d => d.value)) : 0;
  const averageValue = chartData.length ? Math.round(totalValue / chartData.length) : 0;
  
  useEffect(() => {
    const newChartData = datasets[selectedTime];
    setChartHeight(newChartData);
    const timer = setTimeout(() => {
      setIsLoading(false);
    }, 800);
    return () => clearTimeout(timer);
  }, [selectedTime]);
  
  // Alternar período do gráfico
  const handleTimeChange = (time) => {
    setIsLoading(true);
    setSelectedTime(time);
  };
  
  if (isLoading) {
    return (
      <StatisticsSection>
        <ShimmerContainer>
          <ShimmerHeader />
          <ShimmerHeader style={{ width: '40%', height: '20px', marginBottom: '60px' }} />
          
          <ShimmerStatsGrid>
            {Array(3).fill(0).map((_, index) => (
              <ShimmerCard key={index} />
            ))}
          </ShimmerStatsGrid>
          
          <ShimmerChart />
        </ShimmerContainer>
      </StatisticsSection>
    );
  }
  
  return (
    <StatisticsSection>
      <Container>
        <Header>
          <Title
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            Impacto da IA nas Métricas de Vendas
          </Title>
          <Description
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.2 }}
          >
            Descubra como as empresas aumentam a eficiência e 
            expandem as vendas com automação inteligente do Prospector.
          </Description>
        </Header>
        
        <StatsGrid
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.2 }}
        >
          <StatCard variants={itemVariants}>
            <StatValue
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.5, delay: 0.3 }}
            >
              <BsGraphUp />
              78%
            </StatValue>
            <StatTitle>Aumento de Produtividade</StatTitle>
            <StatDescription>
              Os times de vendas que usam IA economizam tempo em tarefas repetitivas e focam nas conversões.
            </StatDescription>
          </StatCard>
          
          <StatCard variants={itemVariants}>
            <StatValue 
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.5, delay: 0.4 }}
            >
              <BsChatDots />
              24/7
            </StatValue>
            <StatTitle>Disponibilidade</StatTitle>
            <StatDescription>
              Atendimento contínuo sem pausas, garantindo que oportunidades nunca sejam perdidas.
            </StatDescription>
          </StatCard>
          
          <StatCard variants={itemVariants}>
            <StatValue
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.5, delay: 0.5 }}
            >
              <BsPeople />
              3.4x
            </StatValue>
            <StatTitle>Mais Conversões</StatTitle>
            <StatDescription>
              Tempo de resposta reduzido de horas para segundos, resultando em taxas de conversão mais altas.
            </StatDescription>
          </StatCard>
        </StatsGrid>
        
        <ChartContainer
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6, delay: 0.2 }}
        >
          <MetricHeader>
            <div>
              <MetricTitle>Crescimento de Vendas</MetricTitle>
              <MetricsRow>
                <TotalValue>
                  R$ {totalValue.toLocaleString('pt-BR')}
                </TotalValue>
                <GrowthBadge positive={growth >= 0}>
                  {growth >= 0 ? '+' : ''}{growth.toFixed(1)}%
                </GrowthBadge>
              </MetricsRow>
            </div>
            <TimeSelector>
              <TimeButton 
                active={selectedTime === 'semana'} 
                onClick={() => handleTimeChange('semana')}
              >
                Semana
              </TimeButton>
              <TimeButton 
                active={selectedTime === 'mes'} 
                onClick={() => handleTimeChange('mes')}
              >
                Mês
              </TimeButton>
              <TimeButton 
                active={selectedTime === 'ano'} 
                onClick={() => handleTimeChange('ano')}
              >
                Ano
              </TimeButton>
            </TimeSelector>
          </MetricHeader>
          
          <div style={{ height: '250px' }}>
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <defs>
                  <linearGradient id="colorValue" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#FF3A1A" stopOpacity={0.25} />
                    <stop offset="95%" stopColor="#FE881F" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" vertical={false} />
                <XAxis dataKey="name" tick={{ fill: '#adb5bd', fontSize: 12 }} axisLine={{ stroke: 'rgba(255,255,255,0.05)' }} tickLine={false} />
                <YAxis tick={{ fill: '#adb5bd', fontSize: 12 }} axisLine={{ stroke: 'rgba(255,255,255,0.05)' }} tickLine={false} />
                <Tooltip cursor={{ stroke: '#FE881F', strokeWidth: 1 }} contentStyle={{ background: 'rgba(12,12,17,0.95)', border: '1px solid #FF3A1A', borderRadius: 8 }} labelStyle={{ color: '#adb5bd' }} itemStyle={{ color: '#FE881F' }} />
                <Area type="monotone" dataKey="value" stroke="#FF3A1A" strokeWidth={3} fill="url(#colorValue)" />
                <Line type="monotone" dataKey="value" stroke="#FF3A1A" strokeWidth={3} dot={{ fill: '#FE881F', stroke: '#0c0c11', strokeWidth: 2, r: 4 }} activeDot={{ r: 6, fill: '#FE881F', stroke: '#0c0c11', strokeWidth: 2 }} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
          
          <SummaryGrid>
            <SummaryCard>
              <SummaryLabel>Período</SummaryLabel>
              <SummaryValue>{selectedTime === 'semana' ? '7 dias' : selectedTime === 'mes' ? '30 dias' : '12 meses'}</SummaryValue>
            </SummaryCard>
            <SummaryCard>
              <SummaryLabel>Maior Valor</SummaryLabel>
              <SummaryValue>R$ {maxValue.toLocaleString('pt-BR')}</SummaryValue>
            </SummaryCard>
            <SummaryCard>
              <SummaryLabel>Média</SummaryLabel>
              <SummaryValue>R$ {averageValue.toLocaleString('pt-BR')}</SummaryValue>
            </SummaryCard>
          </SummaryGrid>
        </ChartContainer>
      </Container>
    </StatisticsSection>
  );
};

